Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, and `CancellationToken` testing:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: creates an HttpClient backed by a fake handler
    private static HttpClient CreateMockClient(
        HttpStatusCode status, string content = "")
    {
        var handler = new MockHttpMessageHandler(status, content);
        return new HttpClient(handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        using var client = CreateMockClient(HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(3000)] // fails the test if it hangs longer than 3 s
    public async Task FetchAsync_Completes_WithinTimeout()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "fast");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler — no third-party mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _status;
        private readonly string _content;

        public MockHttpMessageHandler(HttpStatusCode status, string content)
        {
            _status = status;
            _content = content;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(_status)
            {
                Content = new StringContent(_content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` — MSTest awaits them natively |
| **Timeout** | `[Timeout(ms)]` attribute fails hung tests |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **No mocking lib** | Subclass `HttpMessageHandler` directly — the seam `HttpClient` is designed for |

> **Tip:** Avoid `async void` test methods — MSTest can't observe their exceptions, so failures silently pass.
